import{_ as e,c as o,o as r,R as s}from"./chunks/framework.CIzs38F0.js";const m=JSON.parse('{"title":"1.节点资源压力告警，触发 MemoryPressure 或 DiskPressure","description":"","frontmatter":{},"headers":[],"relativePath":"guide/container/k8s/troubleshooting/3-节点资源压力告警.md","filePath":"guide/container/k8s/troubleshooting/3-节点资源压力告警.md","lastUpdated":1713263180000}'),t={name:"guide/container/k8s/troubleshooting/3-节点资源压力告警.md"},d=s('<h1 id="_1-节点资源压力告警-触发-memorypressure-或-diskpressure" tabindex="-1">1.节点资源压力告警，触发 <code>MemoryPressure</code> 或 DiskPressure <a class="header-anchor" href="#_1-节点资源压力告警-触发-memorypressure-或-diskpressure" aria-label="Permalink to &quot;1.节点资源压力告警，触发 `MemoryPressure` 或 DiskPressure&quot;">​</a></h1><h2 id="_1-1-问题点" tabindex="-1">1.1 问题点 <a class="header-anchor" href="#_1-1-问题点" aria-label="Permalink to &quot;1.1 问题点&quot;">​</a></h2><p>Kubernetes 节点报告内存或磁盘资源压力，标记节点状态为 <code>NotReady</code> 或应用 <code>MemoryPressure</code>、<code>DiskPressure</code> 污点，导致调度器不再将新 Pod 调度到该节点</p><p><strong>影响范围：</strong></p><ul><li>直接影响：节点上的现有 Pod 可能因资源不足而性能下降或被系统强制终止。</li><li>间接影响：集群的整体资源利用率降低，新部署或扩缩容的操作受阻，可能导致服务容量不足或响应延迟</li></ul><h2 id="_1-2-排查方法" tabindex="-1">1.2 排查方法 <a class="header-anchor" href="#_1-2-排查方法" aria-label="Permalink to &quot;1.2 排查方法&quot;">​</a></h2><ol><li><strong>查看节点状态</strong>：使用 <code>kubectl get node</code> 查看所有节点状态，重点关注 <code>Conditions</code> 列中的 <code>MemoryPressure</code> 和 <code>DiskPressure</code> 状态。</li><li><strong>检查资源使用情况</strong>：使用 <code>kubectl top nodes</code> 查看节点的实时资源使用率，对比节点的总资源容量，判断是否存在过度消耗。</li><li><strong>分析资源消耗大户</strong>：使用 <code>kubectl top pods --all-namespaces --sort-by=memory</code> 或 <code>--sort-by=cpu</code> 查找占用资源最多的 Pod，分析其资源使用合理性。</li><li><strong>检查磁盘使用情况</strong>：对于 <code>DiskPressure</code>，使用 <code>df -h</code> 或 <code>du -sh /*</code>（在节点上执行）查看磁盘空间使用情况，定位占用空间大的目录。</li><li><strong>清理资源或调整策略</strong>：根据分析结果，可能需要清理无用数据、优化 Pod 资源请求/限制、调整日志留存策略、迁移部分工作负载到其他节点等</li></ol>',7),a=[d];function c(i,n,l,_,u,h){return r(),o("div",null,a)}const P=e(t,[["render",c]]);export{m as __pageData,P as default};
